// Filter leads: uncontacted + has phone + dedup
const items = $input.all();
const uncontacted = [];
const seenPhones = new Set();
const DAILY_LIMIT = 40;

// Social media / non-website URL patterns
const NOT_WEBSITE = [
  'instagram.com', 'facebook.com', 'fb.com', 'wa.me',
  'api.whatsapp.com', 'whatsapp.com', 'youtube.com', 'youtu.be',
  'twitter.com', 'x.com', 'linkedin.com', 'tiktok.com',
  'linktr.ee', 'linktree.com', 'bit.ly', 'g.page',
  'maps.google.com', 'goo.gl', 'maps.app.goo.gl',
  'zomato.com', 'swiggy.com', 'justdial.com',
  'play.google.com', 'apps.apple.com'
];

function isRealWebsite(url) {
  if (!url || url === '' || url === 'None' || url === 'none' || url === 'N/A') return false;
  const lower = url.toLowerCase().trim();
  if (lower.length < 5) return false;
  // Check if it's a social media / non-website link
  for (const pattern of NOT_WEBSITE) {
    if (lower.includes(pattern)) return false;
  }
  return true;
}

for (const item of items) {
  const status = (item.json.status || '').toString().toLowerCase().trim();
  const phone = (item.json.phone || '').toString().trim();

  // Skip already contacted
  if (['contacted', 'replied', 'converted', 'not_interested'].includes(status)) continue;
  if (!phone || phone.length < 8) continue;

  // Clean phone for WhatsApp (91XXXXXXXXXX)
  let cleanPhone = phone.replace(/[^0-9+]/g, '');
  if (cleanPhone.startsWith('+91')) cleanPhone = cleanPhone.substring(1);
  else if (cleanPhone.startsWith('0')) cleanPhone = '91' + cleanPhone.substring(1);
  else if (!cleanPhone.startsWith('91') && cleanPhone.length === 10) cleanPhone = '91' + cleanPhone;
  if (cleanPhone.length < 12) continue;

  // DEDUP: skip if phone already seen
  if (seenPhones.has(cleanPhone)) continue;
  seenPhones.add(cleanPhone);

  // Check if website is REAL (not instagram/facebook/whatsapp link)
  const rawWebsite = (item.json.website || '').toString().trim();
  const hasRealWebsite = isRealWebsite(rawWebsite);

  uncontacted.push({
    json: {
      business_name: item.json.business_name || 'Business',
      category: item.json.category || '',
      city: item.json.city || '',
      phone: phone,
      email: item.json.email || '',
      website: hasRealWebsite ? rawWebsite : '',
      has_website: hasRealWebsite ? 'YES' : 'NO',
      google_maps_url: item.json.google_maps_url || '',
      rating: item.json.rating || '',
      clean_phone: cleanPhone,
      row_number: items.indexOf(item) + 2
    }
  });

  if (uncontacted.length >= DAILY_LIMIT) break;
}

return uncontacted;

const lead = $('Filter Uncontacted').item.json;
let message = '';

try {
  message = $json.choices[0].message.content.trim();

  // Remove wrapping quotes if model added them
  if ((message.startsWith('"') && message.endsWith('"')) || (message.startsWith("'") && message.endsWith("'"))) {
    message = message.slice(1, -1).trim();
  }

  // Fix common model mistakes
  message = message.replace(/\[Your Name\]/gi, 'Vikash');
  message = message.replace(/\[your name\]/gi, 'Vikash');
  message = message.replace(/\[Name\]/gi, 'Vikash');
  message = message.replace(/- \[.*?\]$/gm, '- Vikash');

  // Fix if model addresses Vikash instead of business
  if (message.toLowerCase().startsWith('hi vikash')) {
    message = message.replace(/^hi vikash[,\s-]*/i, `Hi ${lead.business_name} - `);
  }
  if (message.toLowerCase().startsWith('hello vikash')) {
    message = message.replace(/^hello vikash[,\s-]*/i, `Hi ${lead.business_name} - `);
  }

  // Strip emojis
  message = message.replace(/[\u{1F600}-\u{1F64F}\u{1F300}-\u{1F5FF}\u{1F680}-\u{1F6FF}\u{1F1E0}-\u{1F1FF}\u{2600}-\u{27BF}\u{2700}-\u{27BF}\u{FE00}-\u{FE0F}\u{1F900}-\u{1F9FF}\u{200D}\u{23CF}\u{23E9}-\u{23F3}\u{23F8}-\u{23FA}\u{2934}\u{2935}\u{25AA}-\u{25FE}\u{2B05}-\u{2B07}\u{2B1B}\u{2B1C}\u{2B50}\u{2B55}\u{3030}\u{303D}\u{3297}\u{3299}\u{1FA70}-\u{1FAFF}\u{1FC00}-\u{1FCFF}]/gu, '').trim();
  // Strip exclamation marks
  message = message.replace(/!/g, '.');
  // Clean double spaces
  message = message.replace(/  +/g, ' ');
  // Clean double periods
  message = message.replace(/\.\.+/g, '.');

  // Ensure ends with - Vikash
  if (!message.includes('- Vikash') && !message.includes('-Vikash')) {
    message = message.replace(/\s*$/, ' - Vikash');
  }

  // Ensure starts with Hi [business_name]
  if (!message.toLowerCase().startsWith('hi ')) {
    message = `Hi ${lead.business_name} - ` + message;
  }

} catch(e) {
  // Hardcoded fallback - guaranteed good message
  if (lead.has_website === 'YES') {
    const cat = (lead.category || '').toLowerCase();
    if (cat.match(/restaurant|cafe|bakery|food|kitchen/)) {
      message = `Hi ${lead.business_name} - ${lead.rating || '4+'} stars, great reviews. Do customers WhatsApp you for menu or orders when you are busy? I set up auto-reply systems that handle it. Free 7-day trial, 3 spots this week. Want to try? - Vikash`;
    } else if (cat.match(/salon|spa|beauty|parlour/)) {
      message = `Hi ${lead.business_name} - ${lead.rating || '4+'} stars, clearly popular. I build WhatsApp booking systems where customers pick a slot and book without calling you. Free 7-day trial, 3 spots this week. Interested? - Vikash`;
    } else {
      message = `Hi ${lead.business_name} - ${lead.rating || '4+'} star rating, solid. I set up auto-reply for Google reviews so every customer gets a thank-you reply within minutes. Free 7-day trial, 3 spots this week. Want to try? - Vikash`;
    }
  } else {
    message = `Hi ${lead.business_name} - ${lead.rating || '4+'} stars but no website yet. I build business pages with your menu, prices, location and WhatsApp button. Free 7-day trial, 3 spots this week. Want one? - Vikash`;
  }
}

const phone = lead.clean_phone;
const waLink = `https://wa.me/${phone}?text=${encodeURIComponent(message)}`;

// Telegram card
let tg = `<b>${lead.business_name}</b>\n`;
tg += `${lead.category || 'Business'} | ${lead.city}`;
if (lead.rating) tg += ` | ${lead.rating} stars`;
tg += `\nPhone: ${lead.phone}`;
tg += `\nWebsite: ${lead.has_website === 'YES' ? lead.website : 'None'}`;
tg += `\n\n<i>${message.replace(/</g, '&lt;').replace(/>/g, '&gt;')}</i>`;
tg += `\n\n<a href="${waLink}">TAP TO SEND ON WHATSAPP</a>`;
if (lead.google_maps_url) tg += `\n<a href="${lead.google_maps_url}">View on Maps</a>`;

return {
  json: {
    ...lead,
    ai_message: message,
    wa_link: waLink,
    telegram_text: tg
  }
};
